features.snippet:
reg [7:0] mem [0:127];
reg [6:0] r0_addr_reg;
reg r0_en_reg;
reg [6:0] r1_addr_reg;
reg r1_en_reg;
always @(posedge clk) begin
  if (r0_en_reg) r0_data <= mem[r0_addr_reg];
  if (r1_en_reg) r1_data <= mem[r1_addr_reg];
end

smem rf : UInt<8> [128];
infer mport readPorts_0_data_MPORT = rf[readPorts[0].addr], clock;
infer mport readPorts_1_data_MPORT = rf[readPorts[1].addr], clock;
when writePort.valid :
  infer mport MPORT = rf[writePort.bits.addr], clock;
  MPORT <= writePort.bits.data;
